import React, { useEffect, useState, useMemo } from 'react';
import {
    Box,
    Grid,
    Card,
    CardContent,
    Typography,
    Button
} from '@mui/material';
import {
    People,
    Assignment,
    LocationOn,
    TrendingUp
} from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';
import api from '../../services/api';

// 🔥 CHARTS
import {
    LineChart, Line, XAxis, YAxis, Tooltip, CartesianGrid,
    BarChart, Bar, Cell,
    PieChart, Pie, Legend
} from 'recharts';

// ================= KPI CARD =================
const StatCard = ({ title, value, icon }) => (
    <Card sx={{ borderRadius: 3 }}>
        <CardContent>
            <Box display="flex" justifyContent="space-between">
                <Box>
                    <Typography variant="subtitle2">{title}</Typography>
                    <Typography variant="h5" fontWeight="bold">
                        {value}
                    </Typography>
                </Box>
                {icon}
            </Box>
        </CardContent>
    </Card>
);

// ================= COLORS =================
const COLORS = ['#1976d2', '#2e7d32', '#d32f2f'];

const AdminDashboard = () => {
    const navigate = useNavigate();

    const [stats, setStats] = useState({
        totalEmployees: 0,
        activeEmployees: 0,
        todayPunches: 0,
        pendingApprovals: 0,
        totalDistance: 0,
    });

    const [chartData, setChartData] = useState([]);

    // ================= LOAD DATA =================
    useEffect(() => {
        loadDashboard();
    }, []);

    const loadDashboard = async () => {
        try {
            const res = await api.getDashboardStats();

            setStats({
                totalEmployees: res.data.totalEmployees || 120,
                activeEmployees: res.data.activeEmployees || 95,
                todayPunches: res.data.todayPunches || 45,
                pendingApprovals: res.data.pendingApprovals || 10,
                totalDistance: res.data.totalDistance || 300,
            });

            setChartData(res.data.chart || getDummyTrend());

        } catch (err) {
            console.error(err);
            setChartData(getDummyTrend());
        }
    };

    // ================= DUMMY TREND =================
    const getDummyTrend = () => ([
        { day: 'Mon', punches: 20 },
        { day: 'Tue', punches: 35 },
        { day: 'Wed', punches: 25 },
        { day: 'Thu', punches: 40 },
        { day: 'Fri', punches: 30 },
    ]);

    // ================= PERFORMANCE =================
    const performanceRate = useMemo(() => {
        if (!stats.totalEmployees) return 0;
        return ((stats.activeEmployees / stats.totalEmployees) * 100).toFixed(1);
    }, [stats]);

    const employeeData = useMemo(() => ([
        { name: 'Total', value: stats.totalEmployees },
        { name: 'Active', value: stats.activeEmployees },
    ]), [stats]);

    const allowanceData = [
        { name: 'Approved', value: 60 },
        { name: 'Pending', value: 30 },
        { name: 'Rejected', value: 10 },
    ];

    return (
        <Box sx={{ p: 2 }}>

            {/* ================= HEADER ================= */}
            <Typography variant="h5" fontWeight="bold" mb={2}>
                Admin Dashboard
            </Typography>

            {/* ================= KPI ================= */}
            <Grid container spacing={2}>
                <Grid item xs={12} md={3}>
                    <StatCard title="Employees" value={stats.totalEmployees} icon={<People />} />
                </Grid>

                <Grid item xs={12} md={3}>
                    <StatCard title="Active Employees" value={stats.activeEmployees} icon={<TrendingUp />} />
                </Grid>

                <Grid item xs={12} md={3}>
                    <StatCard title="Today Punches" value={stats.todayPunches} icon={<Assignment />} />
                </Grid>

                <Grid item xs={12} md={3}>
                    <StatCard title="Distance (KM)" value={stats.totalDistance} icon={<LocationOn />} />
                </Grid>
            </Grid>

            {/* ================= QUICK ACTIONS ================= */}
            <Box mt={4}>
                <Typography variant="h6" mb={2}>
                    Quick Actions
                </Typography>

                <Grid container spacing={2}>
                    <Grid item>
                        <Button variant="contained" onClick={() => navigate('/admin/create-user')}>
                            ➕ Create User
                        </Button>
                    </Grid>

                    <Grid item>
                        <Button variant="outlined" onClick={() => navigate('/admin/users')}>
                            👥 View Users
                        </Button>
                    </Grid>

                    <Grid item>
                        <Button variant="outlined" onClick={() => navigate('/admin/employee-tracking')}>
                            📍 Employee Tracking
                        </Button>
                    </Grid>
                </Grid>
            </Box>

            {/* ================= CHARTS ================= */}
            <Grid container spacing={3} mt={2}>

                {/* 🔥 LINE CHART */}
                <Grid item xs={12} md={6}>
                    <Card>
                        <CardContent>
                            <Typography variant="h6">Daily Punch Trend</Typography>

                            <LineChart width={400} height={250} data={chartData}>
                                <CartesianGrid strokeDasharray="3 3" />
                                <XAxis dataKey="day" />
                                <YAxis />
                                <Tooltip />
                                <Line type="monotone" dataKey="punches" stroke="#1976d2" />
                            </LineChart>
                        </CardContent>
                    </Card>
                </Grid>

                {/* 🔥 EMPLOYEE PERFORMANCE */}
                <Grid item xs={12} md={6}>
                    <Card>
                        <CardContent>
                            <Typography variant="h6">
                                Employee Performance
                            </Typography>

                            <Typography variant="body2" sx={{ mb: 2 }}>
                                Active Rate: <b>{performanceRate}%</b>
                            </Typography>

                            <BarChart width={400} height={250} data={employeeData}>
                                <XAxis dataKey="name" />
                                <YAxis />
                                <Tooltip />

                                <Bar dataKey="value">
                                    <Cell fill="#1976d2" />
                                    <Cell fill="#2e7d32" />
                                </Bar>
                            </BarChart>
                        </CardContent>
                    </Card>
                </Grid>

                {/* 🔥 PIE CHART */}
                <Grid item xs={12} md={6}>
                    <Card>
                        <CardContent>
                            <Typography variant="h6">
                                Allowance Status
                            </Typography>

                            <PieChart width={400} height={250}>
                                <Pie
                                    data={allowanceData}
                                    dataKey="value"
                                    nameKey="name"
                                    outerRadius={80}
                                    label
                                >
                                    {allowanceData.map((entry, index) => (
                                        <Cell key={index} fill={COLORS[index]} />
                                    ))}
                                </Pie>
                                <Legend />
                            </PieChart>
                        </CardContent>
                    </Card>
                </Grid>

            </Grid>

            {/* ================= FUTURE SECTION ================= */}
            <Box mt={5}>
                <Typography variant="h6">Advanced Analytics (Future)</Typography>

                <Card sx={{ p: 2, mt: 1 }}>
                    <ul>
                        <li>Top Performing Employees</li>
                        <li>Inactive Employee Alerts</li>
                        <li>Location Heatmap</li>
                        <li>Monthly Distance Trends</li>
                    </ul>
                </Card>
            </Box>

        </Box>
    );
};

export default AdminDashboard;